float compute_average(float I_active, float I_sleep,
                      float t_active, float t_sleep, float period) {
    return (I_active * t_active + I_sleep * t_sleep) / period;
}
int main() {
    float Iact = 30.0; // mA (gồm MCU + Flash + sensor)
    float Islp = 0.02; // mA
    float Tact  = 0.2; // s
    float Tslp  = 599.8; // s
    float Tcycle = 600.0; // 10 phut
    float Iavg = compute_average(Iact, Islp, Tact, Tslp, Tcycle);
    printf("Dong trung binh = %.3f mA\n", Iavg);
    return 0;
}
